const inp = $input.first().json || {};
function fromStr(s){
  s = String(s).trim();
  if (s.startsWith('{')) { try { return JSON.parse(s); } catch(e) {} }
  const m = s.match(/^q=([\s\S]*?)(?:&size=(\d+))?$/);     // format query-string q=...&size=n
  if (m) { const o={q:m[1]}; if(m[2]) o.size=m[2]; return o; }
  return { q: s };
}
let raw = (inp.query !== undefined) ? inp.query : inp;
let args = {};
if (typeof raw === 'string') { args = fromStr(raw); }
else if (raw && typeof raw === 'object') {
  if (raw.q !== undefined || raw.size !== undefined) { args = raw; }
  else {                                                  // wrapper {some_input: "..."}
    const first = Object.values(raw)[0];
    args = (typeof first === 'string') ? fromStr(first) : (first && typeof first==='object' ? first : raw);
  }
}
let q = args.q || args.query || '*';
try { q = decodeURIComponent(q); } catch(e) {}
// Rattrapage erreurs LLM sur recherche par identifiant d'alerte :
q = String(q).replace(/_id\s*:/gi, 'id:');                                  // _id (interne ES) -> id (champ Wazuh)
{ const bare = String(q).trim();
  if (/^\d{8,}\.\d+$/.test(bare)) q = 'id:"' + bare + '"';                   // id brut -> id:"..."
  q = q.replace(/(^|\s|\()id:\s*"?(\d{8,}\.\d+)\*?"?/g, '$1id:"$2"'); }       // id:VALUE(*) -> id:"VALUE"
q = (!q || String(q).trim()==='' || String(q).trim()==='*') ? '*:*' : q;
return [{ json: { q: q, size: Number(args.size) || 15 } }];

const realResp = $('Indexer search').first().json || {};
const enrResp  = $input.first().json || {};
const realHits = (realResp.hits && realResp.hits.hits) || [];
const enrHits  = (enrResp.hits && enrResp.hits.hits) || [];
const emap = {};
for (const h of enrHits) {
  const s = h._source || {}; const a = (s.data||{}).alerte_source || {};
  const aid = a.alert_id;
  if (!aid) continue;
  if (!(aid in emap)) emap[aid] = (s.data||{}).deepseek || null;
}
const alerts = realHits.map(h => {
  const s = h._source || {}; const rule = s.rule||{}; const data = s.data||{}; const ag = s.agent||{}; const sc = s.syscheck||{};
  const aid = s.id; const vt = data.virustotal || null; const vs = (vt && vt.source) || {};
  return { id: aid, ts: s.timestamp, level: Number(rule.level), rule_id: rule.id, desc: rule.description,
           groups: rule.groups, agent: ag.name, srcip: data.srcip||null, srcuser: data.srcuser||null,
           file: sc.path || vs.file || null,
           hash: sc.sha256_after || vs.sha256 || vs.sha1 || sc.sha1_after || vs.md5 || sc.md5_after || null,
           virustotal: vt ? { malicious: vt.malicious, positives: vt.positives, total: vt.total, permalink: vt.permalink } : null,
           analyse_ia: (aid && emap[aid]) ? emap[aid] : null };
});
const t = realResp.hits && realResp.hits.total;
const total = (t && (t.value != null ? t.value : t)) || 0;
return [{ json: { count: alerts.length, total_matching: total,
  note: "total_matching = nb total de VRAIES alertes (DeepSeek exclus). analyse_ia = contexte IA. file/hash/virustotal = pour les alertes de fichier (FIM/VirusTotal).",
  alerts } }];

// Construit la requete d'enrichissement bornee aux alert_id des VRAIES alertes renvoyees.
const hits = (($('Indexer search').first().json.hits)||{}).hits || [];
const ids = hits.map(h => h._source && h._source.id).filter(Boolean);
const q = ids.length
  ? ('rule.groups:ai_enrichment AND data.alerte_source.alert_id:(' + ids.map(i => '"'+i+'"').join(' OR ') + ')')
  : 'data.alerte_source.alert_id:__none__';
const body = JSON.stringify({
  size: Math.max(ids.length, 1),
  sort: [{ timestamp: { order: 'desc' } }],
  _source: ['timestamp','data.alerte_source.alert_id','data.deepseek'],
  query: { query_string: { query: q, default_operator: 'AND' } }
});
return [{ json: { enrichBody: body } }];
